function sortByBits(arr) {
    function countOnes(n) {
        let count = 0;
        while (n > 0) {
            count += n & 1;
            n >>= 1;
        }
        return count;
    }

    return arr.sort((a, b) => {
        let diff = countOnes(a) - countOnes(b);
        return diff !== 0 ? diff : a - b;
    });
}
```


